  imageSource: existing.imageApproved ? existing.imageSource : '',
  imagePrompt: existing.imageApproved ? existing.imagePrompt : '',
  telegramFileId: existing.imageApproved ? existing.telegramFileId : '',
  imageUrl: existing.imageApproved ? existing.imageUrl : '',
  imageMimeType: existing.imageApproved ? existing.imageMimeType : '',
  imageFileName: existing.imageApproved ? existing.imageFileName : '',
};

return [
  {
    json: {
      chatId,
      postContent,
      status: 'pending',
      imageStatus: data[chatId].imageStatus,
      imageApproved: data[chatId].imageApproved,
