  imageSource: existing.imageSource || '',
  imagePrompt: existing.imagePrompt || '',
  telegramFileId: existing.telegramFileId || '',
  imageUrl: existing.imageUrl || '',

  // preserve stored exact image payload
  imageMimeType: existing.imageMimeType || '',
  imageFileName: existing.imageFileName || '',
};

return [
  {
    json: {
      chatId,
      postContent,
      status: 'pending',
      imageStatus: data[chatId].imageStatus,
      imageApproved: data[chatId].imageApproved,
