const data = $getWorkflowStaticData('global');

const chatId = $('Telegram Trigger').first().json.message.chat.id.toString();
const existing = data[chatId] || {};

const hasImage = !!(existing.imageUrl || existing.telegramFileId);

if (!hasImage) {
  return [
    {
      json: {
        chatId,
        ok: false,
        message: 'No pending image found. Generate one with /image ai ... or upload an image first.',
      },
    },
  ];
}

data[chatId] = {
  ...existing,
  imageStatus: 'approved',
  imageApproved: true,
  updatedAt: new Date().toISOString(),
};

return [
  {
    json: {
      chatId,
      ok: true,
      imageStatus: 'approved',
      imageApproved: true,
      message: 'Image approved',
    },
  },
];

