const data = $getWorkflowStaticData('global');
const now = new Date();
const maxAgeHours = 48; // Clean drafts older than 48 hours
let cleanedCount = 0;

for (const chatId in data) {
  const draft = data[chatId];
  if (draft.updatedAt) {
    const draftAge = (now - new Date(draft.updatedAt)) / (1000 * 60 * 60);
    if (draftAge > maxAgeHours) {
      delete data[chatId];
      cleanedCount++;
    }
  }
}

return [{
  json: {
    cleanedCount,
    timestamp: now.toISOString(),
    message: `Cleaned ${cleanedCount} abandoned drafts older than ${maxAgeHours} hours`
  }
}];

